INSERT INTO "public"."culture_recipes" ("id", "title", "description", "time", "difficulty", "servings", "image_url", "is_popular", "ingredients", "steps", "created_at", "superText") VALUES ('1ff90128-11c7-480a-99ac-30fc6f48ce0a', 'Arabaşı Çorbası', 'Kış aylarının vazgeçilmezi.', '45 dk', 'Orta', '6 Kişilik', 'https://blogger.googleusercontent.com/img/a/AVvXsEg9MurpvFaJLmO7VYR0ygz5YyGOHQig_GJZUcMzsSt4d_onWD02ByHtL3ci45HY3Cx2GAb_U12hqxvi6iRebZq95VEiqtwqRB1gcB_ilcYKpgBQ-1proVW1IoQtHEoN3UZQtx4kCFcqF00tZT_lERjAg9XrmQgejYfxZOcNqkOjf_4g1zBrPklP5Vb-d9Ob', 'false', '[{"item":"Un","amount":"5 su bardağı"},{"item":"Su","amount":"Aldığı kadar"},{"item":"Tavuk","amount":"1 bütün"},{"item":"Salça","amount":"2 yemek kaşığı"}]', '["Hamur için suyu kaynatın ve unu yavaşça ekleyerek karıştırın.","Kıvam alan hamuru tepsiye döküp soğumaya bırakın.","Çorba için tavuğu haşlayıp didikleyin.","Tavuk suyu, salça ve baharatlarla çorba kıvamını ayarlayın.","Hamuru baklava dilimi kesip çorba ile servis edin."]', '2026-01-04 11:07:30.096695+00', ''), ('349ee419-3e62-4df4-b7a7-ccc27cc89b7f', 'Testi Kebabı', 'Yozgatın simgesi, dünyaca ünlü lezzet.', '120 dk', 'Orta', '4 Kişilik', 'https://blogger.googleusercontent.com/img/a/AVvXsEg9MurpvFaJLmO7VYR0ygz5YyGOHQig_GJZUcMzsSt4d_onWD02ByHtL3ci45HY3Cx2GAb_U12hqxvi6iRebZq95VEiqtwqRB1gcB_ilcYKpgBQ-1proVW1IoQtHEoN3UZQtx4kCFcqF00tZT_lERjAg9XrmQgejYfxZOcNqkOjf_4g1zBrPklP5Vb-d9Ob', 'true', '[{"item":"Kuşbaşı Kuzu Eti","amount":"1 kg"},{"item":"Arpacık Soğan","amount":"15-20 adet"},{"item":"Sarımsak","amount":"1 baş"},{"item":"Domates","amount":"4 adet"},{"item":"Sivri Biber","amount":"5 adet"},{"item":"Tereyağı","amount":"100 gr"}]', '["Etleri, soğanları, sarımsakları ve doğranmış sebzeleri geniş bir kapta harmanlayın.","Baharatları ve tereyağını ekleyip karıştırmaya devam edin.","Hazırladığınız karışımı testinin içine doldurun.","Testinin ağzını hamur ile hava almayacak şekilde kapatın.","Odun ateşinde veya fırında yaklaşık 2 saat pişirin.","Servis yaparken testiyi kırarak sunum yapın."]', '2026-01-04 11:07:30.096695+00', 'merhaba'), ('ffcada91-530d-449a-8667-a31470f70baa', 'Parmak Çörek', 'Taş fırında pişen çıtır lezzet.', '30 dk', 'Kolay', '2 Kişilik', 'https://blogger.googleusercontent.com/img/a/AVvXsEg9MurpvFaJLmO7VYR0ygz5YyGOHQig_GJZUcMzsSt4d_onWD02ByHtL3ci45HY3Cx2GAb_U12hqxvi6iRebZq95VEiqtwqRB1gcB_ilcYKpgBQ-1proVW1IoQtHEoN3UZQtx4kCFcqF00tZT_lERjAg9XrmQgejYfxZOcNqkOjf_4g1zBrPklP5Vb-d9Ob', 'false', '[{"item":"Kuşbaşı Kuzu Eti","amount":"1 kg"},{"item":"Arpacık Soğan","amount":"15-20 adet"},{"item":"Sarımsak","amount":"1 baş"},{"item":"Domates","amount":"4 adet"},{"item":"Sivri Biber","amount":"5 adet"},{"item":"Tereyağı","amount":"100 gr"}]', '["Etleri, soğanları, sarımsakları ve doğranmış sebzeleri geniş bir kapta harmanlayın.","Baharatları ve tereyağını ekleyip karıştırmaya devam edin.","Hazırladığınız karışımı testinin içine doldurun.","Testinin ağzını hamur ile hava almayacak şekilde kapatın.","Odun ateşinde veya fırında yaklaşık 2 saat pişirin.","Servis yaparken testiyi kırarak sunum yapın."]', '2026-01-04 11:07:30.096695+00', '');